    for (let maskA = 0; maskA < (1 << n); maskA++) {
        for (let maskB = 0; maskB < (1 << n); maskB++) {
            if ((maskA & maskB) !== 0) continue; // A and B must be disjoint

            let xorA = 0;
            let andB = ~0; // All bits set for AND
