                    hasB = true;
                } else {
                    xorC ^= nums[i];
                }
            }

            const currentSum = xorA + (hasB ? andB : 0) + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}

